#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,a[N],c[N];
long long s1,s2;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        c[i]=a[i]-a[i-1];
        if(i>1)
            s1+=(c[i]>0)*c[i],s2+=(c[i]<0)*(-c[i]);
    }
    printf("%lld\n%lld",max(s1,s2),abs(s1-s2)+1);
    return 0;
}
